// Safely extract the agent output regardless of where n8n puts it
const agentJson = $input.item.json;

let raw;
if (typeof agentJson.output === 'string') {
  raw = agentJson.output;
} else if (typeof agentJson.output === 'object' && agentJson.output !== null) {
  raw = JSON.stringify(agentJson.output);
} else if (typeof agentJson.text === 'string') {
  raw = agentJson.text;
} else if (typeof agentJson.response === 'string') {
  raw = agentJson.response;
} else {
  raw = JSON.stringify(agentJson);
}

// Strip markdown fences if present
let cleaned = raw.trim();
if (cleaned.startsWith('```json')) cleaned = cleaned.slice(7);
else if (cleaned.startsWith('```')) cleaned = cleaned.slice(3);
if (cleaned.endsWith('```')) cleaned = cleaned.slice(0, -3);
cleaned = cleaned.trim();

// Find the outermost JSON object even if there is surrounding text
const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');
if (jsonStart !== -1 && jsonEnd !== -1) {
  cleaned = cleaned.slice(jsonStart, jsonEnd + 1);
}

let requirements;
try {
  requirements = JSON.parse(cleaned);
} catch(e) {
  requirements = {
    client_name: 'Parse Error - Check Logs',
    project_title: $('Prepare RFP Metadata').item.json.fileName,
    project_scope: 'Could not parse requirements - review raw AI output',
    budget_range: 'Not specified',
    submission_deadline: 'Not specified',
    project_start_date: 'Not specified',
    contract_duration: 'Not specified',
    evaluation_criteria: [],
    required_sections: [],
    technical_requirements: [],
    key_contacts: [],
    industry: 'Unknown',
    project_type: 'Unknown',
    complexity: 'Medium',
    estimated_value: 0
  };
}

return {
  ...requirements,
  fileName: $('Prepare RFP Metadata').item.json.fileName,
  fileId: $('Prepare RFP Metadata').item.json.fileId,
  fileUrl: $('Prepare RFP Metadata').item.json.fileUrl,
  rawText: $('Prepare RFP Metadata').item.json.rawText,
  receivedAt: $('Prepare RFP Metadata').item.json.receivedAt
};

const requirements = $('Clean & Parse AI Output').item.json;
// HTTP Request node returns the Drive API response directly as $json
// files are under $json.files array
const responseJson = $input.item.json;
const kbFiles = Array.isArray(responseJson.files) ? responseJson.files : [];

const kbSummary = kbFiles.length > 0
  ? kbFiles.map((f, i) => `${i+1}. "${f.name}" - ${f.webViewLink || 'no link'}`).join('\n')
  : 'No past proposals found in knowledge base.';

return {
  requirements,
  kbSummary,
  kbFileCount: kbFiles.length
};

