const req = $('Clean & Parse AI Output').item.json;
const agentJson = $input.item.json;

// Safely read draft content from wherever the agent puts it
let draftContent;
if (typeof agentJson.output === 'string') {
  draftContent = agentJson.output;
} else if (typeof agentJson.output === 'object' && agentJson.output !== null) {
  draftContent = JSON.stringify(agentJson.output);
} else if (typeof agentJson.text === 'string') {
  draftContent = agentJson.text;
} else if (typeof agentJson.response === 'string') {
  draftContent = agentJson.response;
} else {
  draftContent = JSON.stringify(agentJson);
}

const deadlineDate = req.submission_deadline && req.submission_deadline !== 'Not specified'
  ? req.submission_deadline
  : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const estimatedValue = req.estimated_value && req.estimated_value > 0
  ? req.estimated_value
  : null;

return {
  req,
  draftContent,
  deadlineDate,
  estimatedValue,
  opportunityName: `RFP - ${req.client_name} - ${req.project_title}`.substring(0, 120)
};

const items = $input.all();

const sfResult = items.find(i => i.json.id)?.json || {};
const docsResult = items.find(i => i.json.documentId)?.json || {};

const req = $('Clean & Parse AI Output').item.json;

const sfId = sfResult.id || 'SF_ID_UNAVAILABLE';

const docUrl = docsResult.documentId
  ? `https://docs.google.com/document/d/${docsResult.documentId}/edit`
  : 'DOC_URL_UNAVAILABLE';

return {
  salesforceOpportunityId: sfId,
  googleDocUrl: docUrl,
  googleDocId: docsResult.documentId,
  clientName: req.client_name,
  projectTitle: req.project_title,
  submissionDeadline: req.submission_deadline,
  complexity: req.complexity,
  rfpFileUrl: req.fileUrl,
  rfpFileName: req.fileName
};

